package com.ecoPedal.backend.entity;import jakarta.persistence.*;import jakarta.validation.constraints.*;import lombok.*;import java.time.LocalDateTime;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Inheritance(strategy = InheritanceType.JOINED)@Table(name = "compte")public abstract class Compte {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @NotBlank    @Column(nullable = false)    private String nom;    @NotBlank    @Column(nullable = false)    private String prenom;    @Email    @NotBlank    @Column(nullable = false, unique = true)    private String email;    @NotBlank    @Column(nullable = false)    private String motDePasse;    @Column(nullable = false)    private Boolean actif = true;    private LocalDateTime dateCreation;}